import { getVaultCapacity, getMineProduction, getAutoCollectIntervalHours, getBuildingMaxHP } from "/src/lib/gameConstants.js";

// Game state helpers

export const initializeNewBase = async (base44, playerId) => {
  // Create the starter buildings with proper HP values
  const thHP = getBuildingMaxHP('town_hall', 1);
  const armyCampHP = getBuildingMaxHP('army_camp', 1);
  const heroBaseHP = getBuildingMaxHP('hero_base', 1);
  const altarHP = getBuildingMaxHP('altar', 1);
  const mineHP = getBuildingMaxHP('gold_mine', 1);
  const millHP = getBuildingMaxHP('gold_mill', 1);
  const warehouseHP = getBuildingMaxHP('warehouse', 1);
  const defenseTowerHP = getBuildingMaxHP('defense_tower', 1);

  const starterBuildings = [
  { player_id: playerId, building_type: "town_hall", level: 1, grid_x: 35, grid_y: 35, footprint_w: 4, footprint_h: 4, hp: thHP, max_hp: thHP },
  { player_id: playerId, building_type: "army_camp", level: 1, grid_x: 14, grid_y: 14, footprint_w: 8, footprint_h: 8, hp: armyCampHP, max_hp: armyCampHP, capacity: 20 },
  { player_id: playerId, building_type: "hero_base", level: 1, grid_x: 40, grid_y: 35, footprint_w: 1, footprint_h: 1, hp: heroBaseHP, max_hp: heroBaseHP },
  { player_id: playerId, building_type: "altar", level: 1, grid_x: 35, grid_y: 30, footprint_w: 2, footprint_h: 2, hp: altarHP, max_hp: altarHP },
  { player_id: playerId, building_type: "gold_mine", level: 1, grid_x: 30, grid_y: 35, footprint_w: 2, footprint_h: 2, hp: mineHP, max_hp: mineHP, custom_data: { stored_gold: 0 } },
  { player_id: playerId, building_type: "mana_mine", level: 1, grid_x: 40, grid_y: 38, footprint_w: 2, footprint_h: 2, hp: mineHP, max_hp: mineHP, custom_data: { stored_mana: 0 } },
  { player_id: playerId, building_type: "gold_mill", level: 1, grid_x: 30, grid_y: 40, footprint_w: 2, footprint_h: 2, hp: millHP, max_hp: millHP, custom_data: { stored_gold: 0 } },
  { player_id: playerId, building_type: "mana_vault", level: 1, grid_x: 33, grid_y: 40, footprint_w: 2, footprint_h: 2, hp: millHP, max_hp: millHP, custom_data: { stored_mana: 0 } },
  { player_id: playerId, building_type: "warehouse", level: 1, grid_x: 36, grid_y: 40, footprint_w: 2, footprint_h: 2, hp: warehouseHP, max_hp: warehouseHP, capacity: 2000 },
  { player_id: playerId, building_type: "defense_tower", level: 1, grid_x: 42, grid_y: 35, footprint_w: 2, footprint_h: 2, hp: defenseTowerHP, max_hp: defenseTowerHP }];


  const created = await base44.entities.Building.bulkCreate(starterBuildings);

  // Find the hero_base
  const heroBase = created.find((b) => b.building_type === "hero_base");

  // Create starter hero
  const hero = await base44.entities.Hero.create({
    player_id: playerId,
    hero_type: "generic_warrior",
    name: "Varn",
    rarity: "common",
    level: 1,
    hp: 200,
    max_hp: 200,
    attack: 25,
    defense: 15,
    speed: 10,
    stationed_at_building_id: heroBase?.id || "",
    is_unlocked: true,
    portrait: "warrior"
  });

  // Create starter troop stack
  await base44.entities.Troop.create({
    player_id: playerId,
    troop_type: "swordsman",
    count: 10,
    level: 1,
    hp: 50,
    attack: 10,
    defense: 5,
    speed: 8
  });

  return { buildings: created, hero };
};

// Calculate production from mines/mills (stored in custom_data)
export const calculateMineProduction = (buildings, playerBase) => {
  const now = Date.now();
  const lastProduction = playerBase.last_mine_production || now;
  const hoursPassed = (now - lastProduction) / (1000 * 60 * 60);

  if (hoursPassed <= 0) return { totalGold: 0, totalMana: 0, newTime: now };

  let totalGoldOverflow = 0;
  let totalManaOverflow = 0;

  buildings.forEach((b) => {
    if (!b.custom_data) b.custom_data = {};
    const prod = getMineProduction(b.level || 1);
    const produced = Math.floor(prod.production_per_hour * hoursPassed);

    if (b.building_type === "gold_mine" || b.building_type === "gold_mill") {
      const currentStored = b.custom_data.stored_gold || 0;
      const newStored = Math.min(currentStored + produced, prod.storage);
      b.custom_data.stored_gold = newStored;
      if (currentStored + produced > prod.storage) {
        totalGoldOverflow += currentStored + produced - prod.storage;
      }
    }

    if (b.building_type === "mana_mine") {
      const currentStored = b.custom_data.stored_mana || 0;
      const newStored = Math.min(currentStored + produced, prod.storage);
      b.custom_data.stored_mana = newStored;
      if (currentStored + produced > prod.storage) {
        totalManaOverflow += currentStored + produced - prod.storage;
      }
    }
  });

  return { totalGold: totalGoldOverflow, totalMana: totalManaOverflow, newTime: now };
};

// Manual collection from all mines/mills
export const collectFromMines = (buildings, playerBase) => {
  let goldCollected = 0;
  let manaCollected = 0;
  const buildingsToUpdate = [];

  buildings.forEach((b) => {
    if ((b.building_type === "gold_mine" || b.building_type === "gold_mill") && (b.custom_data?.stored_gold || 0) > 0) {
      goldCollected += b.custom_data.stored_gold;
      buildingsToUpdate.push({ ...b, custom_data: { ...b.custom_data, stored_gold: 0 } });
    }
    if (b.building_type === "mana_mine" && (b.custom_data?.stored_mana || 0) > 0) {
      manaCollected += b.custom_data.stored_mana;
      buildingsToUpdate.push({ ...b, custom_data: { ...b.custom_data, stored_mana: 0 } });
    }
  });

  // Apply vault capacity limits
  const goldToAdd = Math.min(goldCollected, Math.max(0, playerBase.gold_capacity - playerBase.gold));
  const manaToAdd = Math.min(manaCollected, Math.max(0, playerBase.mana_capacity - playerBase.mana));

  // Overflow stays in mines (not collected)
  const goldBuildings = buildingsToUpdate.filter((b) => b.building_type.includes('gold'));
  const manaBuildings = buildingsToUpdate.filter((b) => b.building_type.includes('mana'));

  const goldOverflow = goldCollected - goldToAdd;
  const manaOverflow = manaCollected - manaToAdd;

  // Redistribute overflow back to buildings
  if (goldOverflow > 0 && goldBuildings.length > 0) {
    goldBuildings.forEach((b) => {
      b.custom_data.stored_gold = Math.floor(goldOverflow / goldBuildings.length);
    });
  }
  if (manaOverflow > 0 && manaBuildings.length > 0) {
    manaBuildings.forEach((b) => {
      b.custom_data.stored_mana = Math.floor(manaOverflow / manaBuildings.length);
    });
  }

  return {
    goldCollected: goldToAdd,
    manaCollected: manaToAdd,
    buildingsToUpdate
  };
};

export const tickResources = (playerBase, buildings) => {
  if (!playerBase.last_resource_tick) return { goldGain: 0, manaGain: 0, overflowGold: 0, overflowMana: 0 };
  const elapsed = (Date.now() - new Date(playerBase.last_resource_tick).getTime()) / 1000 / 3600;

  const thLevel = playerBase.town_hall_level || 1;
  const autoCollectInterval = getAutoCollectIntervalHours(thLevel);

  let goldGain = 0;
  let manaGain = 0;
  let overflowGold = 0;
  let overflowMana = 0;

  // Calculate production
  const { totalGold, totalMana } = calculateMineProduction(buildings || [], { ...playerBase, last_mine_production: new Date(playerBase.last_resource_tick).getTime() });

  if (autoCollectInterval) {
    // Auto-collect mode (TH15+)
    const hoursSinceLastCollect = playerBase.last_auto_collect ?
    (Date.now() - new Date(playerBase.last_auto_collect).getTime()) / (1000 * 60 * 60) :
    elapsed;

    // Only auto-collect if interval has passed
    if (hoursSinceLastCollect >= autoCollectInterval) {
      goldGain = totalGold;
      manaGain = totalMana;

      // Check vault capacity and calculate overflow
      const goldToAdd = Math.min(goldGain, Math.max(0, playerBase.gold_capacity - playerBase.gold));
      const manaToAdd = Math.min(manaGain, Math.max(0, playerBase.mana_capacity - playerBase.mana));

      overflowGold = goldGain - goldToAdd;
      overflowMana = manaGain - manaToAdd;

      goldGain = goldToAdd;
      manaGain = manaToAdd;
    }
  } else {
    // Manual collection mode (before TH15)
    goldGain = 0;
    manaGain = 0;
  }

  return {
    goldGain: Math.max(0, Math.floor(goldGain)),
    manaGain: Math.max(0, Math.floor(manaGain)),
    overflowGold: Math.max(0, Math.floor(overflowGold)),
    overflowMana: Math.max(0, Math.floor(overflowMana))
  };
};

// Check if a grid position is walkable (not occupied by a building)
// Walls block movement - troops/heroes must pathfind around or attack them
export const isWalkable = (gx, gy, buildings, excludeId) => {
  for (const b of buildings) {
    if (b.id === excludeId) continue;
    if (gx >= b.grid_x && gx < b.grid_x + b.footprint_w &&
    gy >= b.grid_y && gy < b.grid_y + b.footprint_h) {
      return false;
    }
  }
  return true;
};

// A* pathfinding that treats walls as obstacles
export const findPath = (startGx, startGy, endGx, endGy, buildings, excludeId) => {
  const openSet = [{ gx: startGx, gy: startGy, g: 0, h: 0, parent: null }];
  const closedSet = new Set();
  const key = (p) => `${p.gx},${p.gy}`;

  while (openSet.length > 0) {
    // Get node with lowest f = g + h
    openSet.sort((a, b) => a.g + a.h - (b.g + b.h));
    const current = openSet.shift();

    if (current.gx === endGx && current.gy === endGy) {
      // Reconstruct path
      const path = [];
      let node = current;
      while (node) {
        path.unshift({ gx: node.gx, gy: node.gy });
        node = node.parent;
      }
      return path;
    }

    closedSet.add(key(current));

    // Check 4-directional neighbors (can extend to 8 for diagonal)
    const neighbors = [
    { gx: current.gx + 1, gy: current.gy },
    { gx: current.gx - 1, gy: current.gy },
    { gx: current.gx, gy: current.gy + 1 },
    { gx: current.gx, gy: current.gy - 1 }];


    for (const neighbor of neighbors) {
      if (closedSet.has(key(neighbor))) continue;
      if (!isWalkable(neighbor.gx, neighbor.gy, buildings, excludeId)) continue;

      const g = current.g + 1;
      const h = Math.abs(neighbor.gx - endGx) + Math.abs(neighbor.gy - endGy); // Manhattan distance

      const existing = openSet.find((n) => n.gx === neighbor.gx && n.gy === neighbor.gy);
      if (existing) {
        if (g < existing.g) {
          existing.g = g;
          existing.parent = current;
        }
      } else {
        openSet.push({ gx: neighbor.gx, gy: neighbor.gy, g, h, parent: current });
      }
    }
  }

  // No path found
  return null;
};

export const runAutoBattleTick = (heroStates, enemyStates, troopStates) => {
  const log = [];
  let updatedHeroes = heroStates.map((h) => ({ ...h }));
  let updatedEnemies = enemyStates.map((e) => ({ ...e }));
  let updatedTroops = troopStates.map((t) => ({ ...t }));

  // Troops attack enemies
  updatedTroops.forEach((troop) => {
    if (troop.hp <= 0 || troop.count <= 0) return;
    const target = updatedEnemies.find((e) => e.hp > 0);
    if (!target) return;
    const dmg = Math.max(1, troop.attack * troop.count - target.defense);
    target.hp = Math.max(0, target.hp - dmg);
    log.push({ type: "troop_attack", damage: dmg, target_id: target.id });
  });

  // Heroes attack enemies (auto)
  updatedHeroes.forEach((hero) => {
    if (hero.hp <= 0 || hero.manual_control) return;
    const target = updatedEnemies.find((e) => e.hp > 0);
    if (!target) return;
    const dmg = Math.max(1, hero.attack - Math.floor(target.defense * 0.5));
    target.hp = Math.max(0, target.hp - dmg);
    log.push({ type: "hero_attack", hero_id: hero.id, damage: dmg, target_id: target.id });
  });

  // Enemies attack troops
  updatedEnemies.forEach((enemy) => {
    if (enemy.hp <= 0) return;
    const aliveTroop = updatedTroops.find((t) => t.count > 0);
    if (aliveTroop) {
      const dmg = Math.max(1, enemy.attack - aliveTroop.defense);
      aliveTroop.hp = Math.max(0, aliveTroop.hp - dmg);
      if (aliveTroop.hp <= 0) {
        aliveTroop.count = Math.max(0, aliveTroop.count - 1);
        aliveTroop.hp = aliveTroop.max_hp;
      }
      log.push({ type: "enemy_attack", damage: dmg });
    } else {
      const heroTarget = updatedHeroes.find((h) => h.hp > 0);
      if (heroTarget) {
        const dmg = Math.max(1, enemy.attack - heroTarget.defense);
        heroTarget.hp = Math.max(0, heroTarget.hp - dmg);
        log.push({ type: "enemy_attack_hero", damage: dmg, hero_id: heroTarget.id });
      }
    }
  });

  const allEnemiesDead = updatedEnemies.every((e) => e.hp <= 0);
  const allPlayersDead = updatedHeroes.every((h) => h.hp <= 0) && updatedTroops.every((t) => t.count <= 0);

  return {
    heroStates: updatedHeroes,
    enemyStates: updatedEnemies,
    troopStates: updatedTroops,
    log,
    victory: allEnemiesDead,
    defeat: allPlayersDead
  };
};
